{"inp":{"code":"# Sensitivity scenarios for different EV/EBITDA multiples using the implied EBITDA
ebitda = 11583387418.673864
multiples = [6.5, 7.5, 8.5]
results = {}
for m in multiples:
    ev_t = ebitda * m
    market_cap_t = ev_t - div_liq
    price_t = market_cap_t / shares
    results[m] = {'ev_target': ev_t, 'market_cap_target': market_cap_t, 'price_target': price_t}

import json
print(json.dumps(results, indent=2))

# print nicely
for m, res in results.items():
    print(f"EV/EBITDA={m:.1f} -> Price target R${res['price_target']:.2f}")
"} }

